\begin{equation}\label{Lipschitz_condition}
\| \boldsymbol{f}_r(t, \boldsymbol{x}_1, r(t); \Theta) - \boldsymbol{f}_r(t, \boldsymbol{x}_2, r(t); \Theta) \| \leq L \| \boldsymbol{x}_1 -\boldsymbol{x} _2 \|.
\end{equation}

